// ============================================
// DETECTAR INTENCIÓN - ECOCUPON
// ============================================

const input = $input.item.json;
const message = input.message || '';
const channel = input.channel || 'web';

// Detectar intención basada en keywords
const intentPatterns = {
  'recycling_point': ['punto', 'reciclar', 'dónde', 'ubicación', 'dirección'],
  'coupon_status': ['cupón', 'descuento', 'vigencia', 'vencido'],
  'material_info': ['plástico', 'vidrio', 'cartón', 'papel', 'metal'],
  'customer_support': ['problema', 'ayuda', 'consulta', 'reclamo'],
  'registration': ['registrar', 'crear', 'cuenta', 'unirme']
};

let detectedIntent = 'general';
let confidence = 0.5;

for (const [intent, keywords] of Object.entries(intentPatterns)) {
  const matches = keywords.filter(kw => message.toLowerCase().includes(kw));
  if (matches.length > 0) {
    detectedIntent = intent;
    confidence = Math.min(0.5 + (matches.length * 0.15), 0.95);
    break;
  }
}

// Construir respuesta según intención
const responses = {
  'recycling_point': {
    message: '🌟 ¡Gracias por reciclar! Tenemos 3 puntos cerca de ti:\n\n📍 Santiago Centro - Av. OHiggins 1234\n📍 Providencia - Av. Providencia 567\n📍 Las Condes - Av. Apoquindo 890\n\nHorario: Lunes a Viernes 9:00-18:00\n\n¿Te gustaría que te enviemos la ubicación exacta?',
    action: 'show_points',
    follow_up: true
  },
  'coupon_status': {
    message: '🎫 Para verificar tu cupón, necesito el código. ¿Me lo puedes compartir? (ej: ECO-ABC123)',
    action: 'request_coupon_code',
    follow_up: true
  },
  'material_info': {
    message: '♻️ ¡Excelente pregunta! Aceptamos:\n\n🥤 Plásticos (PET, HDPE)\n🍾 Vidrio (botellas, frascos)\n📦 Cartón (limpio y seco)\n📄 Papel (todo tipo)\n🥫 Metal (latas, aluminio)\n\nPor cada kg reciclado, recibes $100 de descuento. ¿Qué material quieres reciclar?',
    action: 'provide_info',
    follow_up: true
  },
  'customer_support': {
    message: '🤝 Lamento escuchar eso. Voy a crear un ticket para que te contactemos pronto. ¿Me puedes dejar tu email o teléfono?',
    action: 'create_ticket',
    follow_up: true
  },
  'registration': {
    message: '🎉 ¡Bienvenido a Ecocupon! Para registrarte necesito:\n\n1️⃣ Tu email\n2️⃣ Tu nombre\n\n¿Me los compartes?',
    action: 'start_registration',
    follow_up: true
  },
  'general': {
    message: '🌱 ¡Hola! Soy el asistente virtual de Ecocupon.\n\nTe puedo ayudar con:\n♻️ Puntos de reciclaje\n🎫 Cupones y descuentos\n📦 Materiales aceptados\n🤝 Soporte\n\n¿En qué puedo ayudarte?',
    action: 'show_menu',
    follow_up: true
  }
};

const response = responses[detectedIntent] || responses['general'];

return {
  json: {
    ...input,
    detected_intent: detectedIntent,
    confidence,
    response_message: response.message,
    response_action: response.action,
    requires_follow_up: response.follow_up,
    processed_at: new Date().toISOString()
  }
};

// ============================================
// REGISTRAR INTERACCIÓN EN SUPABASE
// ============================================

const interaction = $input.item.json;

const interactionData = {
  customer_id: interaction.customer_id || null,
  channel: interaction.channel || 'web',
  interaction_type: interaction.detected_intent || 'general',
  subject: `Consulta vía ${interaction.channel}`,
  message: interaction.message || '',
  response: interaction.response_message || '',
  status: interaction.requires_follow_up ? 'in_progress' : 'resolved',
  metadata: {
    confidence: interaction.confidence,
    action: interaction.response_action,
    processed_at: interaction.processed_at
  }
};

return { json: { interaction: interactionData, original: interaction } };

